import * as React from "react";

export interface TdHeroCta {
  label: string;
  href: string;
  variant?: "primary" | "secondary";
}

export interface TdHeroProps {
  eyebrow?: string;
  headline: string;
  body?: string;
  ctas?: TdHeroCta[];
  /** Optional background image URL; falls back to a CSS bokeh gradient. */
  backgroundImage?: string;
  className?: string;
}

const bokehBackground = (img?: string): React.CSSProperties => ({
  backgroundImage: [
    "radial-gradient(circle at 18% 22%, rgba(255,255,255,0.18) 0, transparent 32%)",
    "radial-gradient(circle at 78% 68%, rgba(255,255,255,0.12) 0, transparent 28%)",
    "radial-gradient(circle at 50% 100%, var(--td-secondary, #234F98) 0, transparent 55%)",
    "linear-gradient(135deg, var(--td-primary, #2E6554) 0%, var(--td-secondary, #234F98) 100%)",
    img ? `url(${img})` : "",
  ]
    .filter(Boolean)
    .join(", "),
  backgroundSize: "cover",
  backgroundPosition: "center",
  backgroundBlendMode: img ? "overlay" : "normal",
});

export function TdHero({
  eyebrow,
  headline,
  body,
  ctas = [],
  backgroundImage,
  className = "",
}: TdHeroProps) {
  return (
    <section
      className={`relative isolate overflow-hidden ${className}`.trim()}
      style={bokehBackground(backgroundImage)}
    >
      <div className="mx-auto flex max-w-5xl flex-col items-start gap-8 px-6 py-28 md:py-40">
        {eyebrow ? (
          <span className="inline-block rounded-full bg-white/15 px-3 py-1 text-xs font-medium uppercase tracking-[0.18em] text-white backdrop-blur">
            {eyebrow}
          </span>
        ) : null}
        <h1 className="max-w-3xl text-4xl font-semibold leading-[1.05] tracking-tight text-white md:text-6xl">
          {headline}
        </h1>
        {body ? (
          <p className="max-w-xl text-base leading-relaxed text-white/85 md:text-lg">{body}</p>
        ) : null}
        {ctas.length > 0 ? (
          <div className="flex flex-col items-start gap-3">
            {ctas.map((cta) => (
              <a
                key={cta.href}
                href={cta.href}
                className="inline-flex h-11 items-center rounded-md px-6 text-sm font-medium transition-opacity hover:opacity-90"
                style={{
                  backgroundColor:
                    cta.variant === "secondary"
                      ? "rgba(255,255,255,0.12)"
                      : "#ffffff",
                  color:
                    cta.variant === "secondary"
                      ? "#ffffff"
                      : "var(--td-primary, #2E6554)",
                  border:
                    cta.variant === "secondary"
                      ? "1px solid rgba(255,255,255,0.45)"
                      : "1px solid transparent",
                }}
              >
                {cta.label}
              </a>
            ))}
          </div>
        ) : null}
      </div>
    </section>
  );
}

export default TdHero;
